#include <bits/stdc++.h>
#define ll long long
#define CI const int
#define PII pair<int,int>
#define mk(x,y) make_pair(x,y)
#define ull unsigned long long
#define inf 0x3f3f3f3f
#define NoAns puts("-1")
using namespace std;
inline ll read()
{
	ll x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(ll x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
CI MAXN = 1e5 + 5, MOD = 1e4+7;
ll n, m, a[MAXN], c[MAXN], cnt[MAXN][2], sum[MAXN][2];
int main (void)
{
	n = read(), m = read();
	for (int i = 1; i <= n; ++i)
	{
		a[i] = read();
	}
	for (int i = 1; i <= n; ++i)
	{
		c[i] = read();
		++cnt[c[i]][i & 1];
		sum[c[i]][i & 1] = (sum[c[i]][i & 1] + i);
	}
	ll ans = 0;
	for (int i = 1; i <= n; ++i)
	{
		ans = (ans + a[i] * (i * (cnt[c[i]][i & 1] - 2) + sum[c[i]][i & 1]) ) ;
	}
	write(ans%MOD);
	return false;
}
